// js/db.js
// Setup Dexie Database for Personal OS

const db = new Dexie('PersonalOSDB');

// Define database schema
// ++id means auto-incremented primary key.
// String ids can also be used, but let's stick to Dexie's auto-increment or custom unique strings.
// For UUIDs, we can just use the 'id' field as a primary key without ++ if we generate it manually, 
// but using string IDs is fine. Let's use string UUIDs generated by us.

db.version(2).stores({
    projects: 'id, title, status, progress, createdAt, updatedAt', // status: Active, On Hold, Completed, Archived
    tasks: 'id, title, status, priority, deadline, projectId, createdAt, updatedAt', // colId can represent status or we can just map it
    notes: 'id, title, folder, isPinned, projectId, createdAt, updatedAt',
    finances: 'id, type, amount, category, date, projectId, createdAt', // type: income, expense
    events: 'id, title, date, type, projectId, createdAt' // type: Acara, Pengingat
,
    inbox: 'id, content, type, createdAt'
});

// Helper UUID generator
function generateUUID() {
    return 'id_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}

// Global DB Helper Functions
const OS_DB = {
    // --- PROJECTS ---
    async addProject(data) {
        const id = generateUUID();
        const now = new Date().toISOString();
        const project = { id, ...data, progress: 0, createdAt: now, updatedAt: now };
        await db.projects.put(project);
        return project;
    },
    async getProjects() {
        return await db.projects.toArray();
    },
    async getProjectById(id) {
        return await db.projects.get(id);
    },
    async updateProject(id, data) {
        data.updatedAt = new Date().toISOString();
        return await db.projects.update(id, data);
    },
    async deleteProject(id) {
        return await db.projects.delete(id);
    },

    // Migrasi data dari LocalStorage ke IndexedDB (Hanya dijalankan sekali)
    async migrateFromLocalStorage() {
        const isMigrated = localStorage.getItem('is_migrated_to_indexeddb');
        if (isMigrated === 'true') return;

        console.log("Memulai migrasi dari localStorage ke IndexedDB...");

        // 1. Migrasi Notes
        try {
            const lsNotes = JSON.parse(localStorage.getItem('personalos_notes')) || [];
            if (lsNotes.length > 0) {
                const notesToInsert = lsNotes.map(n => ({
                    id: n.id || generateUUID(),
                    title: n.title || 'Untitled',
                    content: n.content || '',
                    folder: n.category || 'Personal',
                    isPinned: n.isPinned || false,
                    projectId: null,
                    createdAt: n.date ? new Date(n.date).toISOString() : new Date().toISOString(),
                    updatedAt: n.date ? new Date(n.date).toISOString() : new Date().toISOString()
                }));
                await db.notes.bulkPut(notesToInsert);
            }
        } catch(e) { console.error("Gagal migrasi notes", e); }

        // 2. Migrasi Tasks
        try {
            const lsTasksData = JSON.parse(localStorage.getItem('tasks_board_v2'));
            if (lsTasksData && lsTasksData.columns) {
                let tasksToInsert = [];
                lsTasksData.columns.forEach(col => {
                    if(col.tasks) {
                        col.tasks.forEach(t => {
                            tasksToInsert.push({
                                id: t.id || generateUUID(),
                                title: t.title,
                                status: col.title, // 'Akan Dikerjakan', dll
                                colId: col.id,
                                priority: t.priority || 'Normal',
                                deadline: t.deadline || '',
                                timeStart: t.timeStart || '',
                                timeEnd: t.timeEnd || '',
                                desc: t.desc || '',
                                subtasks: t.subtasks || [],
                                projectId: null,
                                createdAt: new Date().toISOString(),
                                updatedAt: new Date().toISOString()
                            });
                        });
                    }
                });
                await db.tasks.bulkPut(tasksToInsert);
            }
        } catch(e) { console.error("Gagal migrasi tasks", e); }

        // 3. Migrasi Finance
        try {
            const lsFinance = JSON.parse(localStorage.getItem('finance_transactions')) || [];
            if (lsFinance.length > 0) {
                const financeToInsert = lsFinance.map(f => ({
                    id: f.id || generateUUID(),
                    type: f.type, // income / expense
                    amount: f.amount,
                    category: f.category,
                    date: f.date,
                    note: f.note || '',
                    projectId: null,
                    createdAt: new Date().toISOString()
                }));
                await db.finances.bulkPut(financeToInsert);
            }
        } catch(e) { console.error("Gagal migrasi finance", e); }

        // 4. Migrasi Calendar Events
        try {
            const lsEvents = JSON.parse(localStorage.getItem('calendar_events')) || [];
            if (lsEvents.length > 0) {
                const eventsToInsert = lsEvents.map(e => ({
                    id: e.id || generateUUID(),
                    title: e.title,
                    date: e.date,
                    timeStart: e.timeStart || '',
                    timeEnd: e.timeEnd || '',
                    type: e.type || 'Acara',
                    category: e.category || '',
                    projectId: null,
                    createdAt: new Date().toISOString()
                }));
                await db.events.bulkPut(eventsToInsert);
            }
        } catch(e) { console.error("Gagal migrasi events", e); }

        localStorage.setItem('is_migrated_to_indexeddb', 'true');
        console.log("Migrasi selesai!");
    }
};

// Auto jalankan migrasi saat db.js di load
document.addEventListener('DOMContentLoaded', () => {
    OS_DB.migrateFromLocalStorage();
});
